class Node: 
  def __init__(self, data): 
    self.data = data 
    self.children = [] 

def buildTree(relationships): 
  tree = {} 
  for parent, child in relationships: 
    if parent not in tree: 
      tree[parent] = Node(parent) 
    parent_node = tree[parent] 
    if child not in tree: 
      tree[child] = Node(child) 
    child_node = tree[child] 
    parent_node.children.append(child_node) 
  return tree[1]

import json

def convert_to_json(data):
    """Convert any data format into a JSON format."""
    try:
        # check if data is string
        if isinstance(data, str):
            return json.loads(data)
        # check if data is xml
        elif data.tag == 'note':
            return {
                'to': data.find('to').text,
                'from': data.find('from').text, 
                'heading': data.find('heading').text,
                'body': data.find('body').text,
            }
    except Exception as e:
        raise e

