def filter_list(strings):
    unique_strings = []
    for string in strings:
        if string not in unique_strings:
            unique_strings.append(string)
    return unique_strings

strings = ["abc", "def", "abc", "ghi", "jkl", "mno", "abc", "pqr"]
filtered_strings = filter_list(strings)
print(filtered_strings)

# Output: ['abc', 'def', 'ghi', 'jkl', 'mno', 'pqr']

def array_to_char_count_dict(arr):
    character_count = {}
    for string in arr:
        for char in string:
            if char in character_count:
                character_count[char] += 1
            else:
                character_count[char] = 1
    return character_count

arr = ["hello", "world", "the"]
print(array_to_char_count_dict(arr))
# Output: {'h': 1, 'e': 2, 'l': 3, 'o': 2, 'w': 1, 'r': 1, 'd': 1, 't': 1}
